code.JavaScript:
const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
let n;
let a;
rl.on('line', (input) => {
    if (!n) {
        n = parseInt(input);
    } else {
        a = input.split(' ').map(x => parseInt(x));
        let min = Math.min(...a);
        let count = 0;
        for (let i = 0; i < n; i++) {
            count += a[i] - min;
        }
        console.log(count);
        rl.close();
    }
});
